import { Avatar, Column, Icon, Row, Text } from 'native-base'
import { memo } from 'react'
import { Feather } from '@native-base/icons'

import { DataItem } from '~/data'

export type ListItemProps = {
  data: DataItem
}

export const ListItem = memo<ListItemProps>(
  ({ data: { title, subtitle, avatar, location, startDate, endDate, description } }) => {
    return (
      <Row px={4} py={2} space={2}>
        <Avatar source={typeof avatar === 'string' ? { uri: avatar } : avatar} />
        <Column flex={1}>
          <Text fontWeight={800} fontSize={15}>
            {title}
            <Text fontWeight={400} color="muted.500">
              {' · '}
              {subtitle}
            </Text>
          </Text>

          {description && <Text mt={1}>{description}</Text>}

          <Text color="muted.500" mt={1}>
            <Icon color="muted.500" size="4" as={Feather} name="map-pin" /> {location}
          </Text>
          <Text color="muted.500">
            <Icon color="muted.500" size="4" as={Feather} name="calendar" />{' '}
            {startDate.format('MMMM YYYY')} - {endDate.format('MMMM YYYY')}
          </Text>
        </Column>
      </Row>
    )
  }
)
